module RefModule(
    input [3:0] a,
    input [3:0] b,
    input [3:0] c,
    output [4:0] sum
);
    wire [4:0] sum_ab, sum_abc;

    // Perform initial addition of a and b
      wire _n01 = a[0] ^ b[0];
  wire _c01 = a[0] & b[0];
  wire _n02 = a[1] ^ b[1] ^ _c01;
  wire _c02 = (a[1] & b[1]) | (a[1] & _c01) | (b[1] & _c01);
  wire _n03 = a[2] ^ b[2] ^ _c02;
  wire _c03 = (a[2] & b[2]) | (a[2] & _c02) | (b[2] & _c02);
  wire _n04 = a[3] ^ b[3] ^ _c03;
  wire _c04 = (a[3] & b[3]) | (a[3] & _c03) | (b[3] & _c03);
  assign sum_ab = {_n01, _n02, _n03, _n04};

    // Perform addition of the intermediate result with c
    assign sum_abc = sum_ab + c;

    // Output the final sum
    assign sum = sum_abc;

endmodule
